extern "C" const char *m14_lane_token(const forge::UnitSpec *units, size_t count) {
    // Lane token digest over newline-joined descriptor lines sorted by unit name.
    static std::string cached;

    std::vector<const forge::UnitSpec *> sorted;
    sorted.reserve(count);
    for (size_t i = 0; i < count; ++i) {
        sorted.push_back(&units[i]);
    }
    std::sort(sorted.begin(), sorted.end(),
              [](const forge::UnitSpec *a, const forge::UnitSpec *b) { return a->name < b->name; });

    std::ostringstream joined;
    for (size_t i = 0; i < sorted.size(); ++i) {
        if (i) {
            joined << '\n';
        }
        joined << descriptor_line(*sorted[i]);
    }

    cached = digest_hex(joined.str());
    return cached.c_str();
}

extern "C" int m14_checkpoint_valid(const char *on_disk_token, const char *expected_token) {
    if (on_disk_token == nullptr || expected_token == nullptr) {
        return 0;
